  "pageId": "6-2-the-economic-climate",
  "pageName": "6.2 The Economic Climate",
  "source": "tf",
  "type": "tf",
  "marks": 1,
  "question": "When unemployment falls, businesses will find it easier and cheaper to hire new workers.",
